#include<bits/stdc++.h>
using namespace std;
const int N = 1e7 + 5;
int mi[10001],cnt1;
int mii(int n,int m){
	int i;
	for(i=0;pow(2,i)<=m;i++);
	return i-1;
}
int n, m, ant = 1;
int main() {
	cin >> n >> m;
    int x=mii(n,m);
    if(pow(2,x)<n){
        for(int i=n;i<=m;i++){
            x=i;
            int num=0;
            for(int j=2;x>1;j++){
                if(x%j==0){
                    x/=j;
                    num++;
                    j--;
                }
            }
            ant=max(ant,num);
        }
        cout<<ant;
    }else{
	cout << mii(n,m);}
	return 0;
}
